import { useState } from 'react'
import { createFileRoute } from '@tanstack/react-router'
import { useQuery } from '@tanstack/react-query'
import { z } from 'zod'
import { getRegistry } from '../server/registry'
import { ToolshopHeader } from '../components/ToolshopHeader'
import { CardGrid } from '../components/CardGrid'
import { SparkLauncher } from '../components/SparkLauncher'
import type { ResolvedManifest } from '../types/manifest'

const searchSchema = z.object({
  search: z.string().optional().catch(undefined),
})

export const Route = createFileRoute('/')({
  validateSearch: searchSchema,
  component: HomePage,
})

function filterSpreelets(
  spreelets: ResolvedManifest[],
  search: string,
): ResolvedManifest[] {
  const term = search.toLowerCase()
  return spreelets.filter(
    (s) =>
      s.manifest.name.toLowerCase().includes(term) ||
      s.manifest.description.toLowerCase().includes(term) ||
      s.manifest.tags.some((t) => t.toLowerCase().includes(term)),
  )
}

function HomePage() {
  const { search } = Route.useSearch()
  const navigate = Route.useNavigate()
  const [sparkTarget, setSparkTarget] = useState<ResolvedManifest | null>(null)

  const { data: registry, isLoading } = useQuery({
    queryKey: ['registry'],
    queryFn: () => getRegistry(),
    staleTime: 5 * 60 * 1000,
  })

  const spreelets = registry?.spreelets ?? []
  const filtered = search ? filterSpreelets(spreelets, search) : spreelets

  return (
    <div className="min-h-screen">
      <ToolshopHeader
        search={search ?? ''}
        onSearchChange={(value) =>
          navigate({ search: { search: value || undefined } })
        }
      />
      <main className="mx-auto max-w-5xl px-6 py-8">
        <CardGrid
          spreelets={filtered}
          isLoading={isLoading}
          onQuickOpen={setSparkTarget}
        />
      </main>
      <SparkLauncher
        resolved={sparkTarget}
        onClose={() => setSparkTarget(null)}
      />
    </div>
  )
}

import { Skeleton } from '@spreetail/spreeform'
import { SpreeletCard } from './SpreeletCard'
import type { ResolvedManifest } from '../types/manifest'

interface CardGridProps {
  spreelets: ResolvedManifest[]
  isLoading?: boolean
  onQuickOpen?: (resolved: ResolvedManifest) => void
}

export function CardGrid({ spreelets, isLoading, onQuickOpen }: CardGridProps) {
  if (isLoading) {
    return (
      <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
        {Array.from({ length: 3 }).map((_, i) => (
          <div key={i} className="space-y-3 rounded-xl border border-border p-6">
            <div className="flex items-start gap-3">
              <Skeleton className="h-10 w-10 rounded-lg" />
              <div className="flex-1 space-y-2">
                <Skeleton className="h-4 w-24" />
                <Skeleton className="h-3 w-full" />
              </div>
            </div>
            <div className="flex gap-1.5">
              <Skeleton className="h-5 w-16 rounded-full" />
              <Skeleton className="h-5 w-12 rounded-full" />
              <Skeleton className="h-5 w-14 rounded-full" />
            </div>
            <Skeleton className="h-8 w-20" />
          </div>
        ))}
      </div>
    )
  }

  if (spreelets.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-16 text-center">
        <p className="text-lg text-muted-foreground">No tools found</p>
        <p className="mt-1 text-sm text-muted-foreground">
          Try a different search term
        </p>
      </div>
    )
  }

  const sorted = [...spreelets].sort((a, b) =>
    a.manifest.name.localeCompare(b.manifest.name),
  )

  return (
    <div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
      {sorted.map((resolved) => (
        <SpreeletCard
          key={resolved.manifest.id}
          resolved={resolved}
          onQuickOpen={onQuickOpen}
        />
      ))}
    </div>
  )
}

import { createServerFn } from '@tanstack/react-start'
import {
  RegistrySchema,
  SpreeletManifestSchema,
  type ResolvedManifest,
  type ResolvedRegistry,
  type RegistryEntry,
} from '../types/manifest'
import registryData from '../data/registry.json'

const FETCH_TIMEOUT_MS = 3000

/**
 * Resolve relative URLs in a manifest against the origin it was fetched from.
 * This makes manifests portable — apps use relative paths like "/api/summary"
 * and the Toolshop resolves them based on where the manifest lives.
 */
function resolveManifestUrls(
  manifest: ReturnType<typeof SpreeletManifestSchema.parse>,
  manifestUrl: string,
): void {
  let origin: string
  try {
    origin = new URL(manifestUrl).origin
  } catch {
    return // Can't resolve if manifestUrl isn't a valid URL
  }

  const resolve = (path: string) =>
    path.startsWith('/') ? `${origin}${path}` : path

  if (manifest.url) manifest.url = resolve(manifest.url)
  if (manifest.surfaces?.card?.summaryEndpoint) {
    manifest.surfaces.card.summaryEndpoint = resolve(manifest.surfaces.card.summaryEndpoint)
  }
  if (manifest.surfaces?.spark?.component) {
    manifest.surfaces.spark.component = resolve(manifest.surfaces.spark.component)
  }
  if (manifest.surfaces?.full?.url) {
    manifest.surfaces.full.url = resolve(manifest.surfaces.full.url)
  }
}

async function fetchManifest(
  entry: RegistryEntry,
): Promise<ResolvedManifest> {
  try {
    const controller = new AbortController()
    const timeout = setTimeout(() => controller.abort(), FETCH_TIMEOUT_MS)

    const response = await fetch(entry.manifestUrl, {
      signal: controller.signal,
      headers: { Accept: 'application/json' },
    })
    clearTimeout(timeout)

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`)
    }

    const data = await response.json()
    const manifest = SpreeletManifestSchema.parse(data)

    if (manifest.id !== entry.id) {
      throw new Error(
        `Manifest id mismatch: expected "${entry.id}" but got "${manifest.id}"`,
      )
    }

    resolveManifestUrls(manifest, entry.manifestUrl)

    return { manifest, source: 'live' }
  } catch (err) {
    const error =
      err instanceof Error ? err.message : 'Unknown fetch error'

    if (entry.fallback) {
      return {
        manifest: entry.fallback,
        source: 'fallback',
        error: `Live fetch failed (${error}), using fallback`,
      }
    }

    throw new Error(
      `Failed to fetch manifest for ${entry.id} and no fallback available: ${error}`,
    )
  }
}

export const getRegistry = createServerFn({ method: 'GET' }).handler(
  async () => {
    const registry = RegistrySchema.parse(registryData)

    const results = await Promise.all(
      registry.spreelets.map((entry) => fetchManifest(entry)),
    )

    const resolved: ResolvedRegistry = {
      domain: registry.domain,
      spreelets: results,
    }

    return resolved
  },
)

